(function (global, factory) {
    typeof exports === 'object' && typeof module !== 'undefined' ? factory(exports) :
    typeof define === 'function' && define.amd ? define(['exports'], factory) :
    (global = typeof globalThis !== 'undefined' ? globalThis : global || self, factory(global.Stomp = {}));
})(this, (function (exports) { 'use strict';

    // Simplified STOMP implementation for basic functionality
    class Client {
        constructor(ws) {
            this.ws = ws;
            this.connected = false;
            this.subscriptions = {};
            this.counter = 0;
        }
        
        connect(headers, connectCallback, errorCallback) {
            this.ws.onopen = () => {
                // Send CONNECT frame
                const connectFrame = this._buildFrame('CONNECT', headers);
                this.ws.send(connectFrame);
                
                // Set up message handler
                this.ws.onmessage = (event) => {
                    const frame = this._parseFrame(event.data);
                    if (frame.command === 'CONNECTED') {
                        this.connected = true;
                        if (connectCallback) connectCallback(frame);
                    } else if (frame.command === 'MESSAGE') {
                        const subscriptionId = frame.headers.subscription;
                        if (this.subscriptions[subscriptionId]) {
                            this.subscriptions[subscriptionId](frame);
                        }
                    } else if (frame.command === 'ERROR' && errorCallback) {
                        errorCallback(new Error(frame.headers.message || 'STOMP error'));
                    }
                };
                
                this.ws.onerror = (error) => {
                    if (errorCallback) errorCallback(error);
                };
                
                this.ws.onclose = () => {
                    this.connected = false;
                };
            };
        }
        
        disconnect(disconnectCallback) {
            if (this.connected) {
                const frame = this._buildFrame('DISCONNECT');
                this.ws.send(frame);
                this.connected = false;
            }
            this.ws.close();
            if (disconnectCallback) disconnectCallback();
        }
        
        send(destination, headers = {}, body = '') {
            if (!this.connected) {
                throw new Error('Not connected');
            }
            
            const sendHeaders = Object.assign({}, headers, { destination });
            const frame = this._buildFrame('SEND', sendHeaders, body);
            this.ws.send(frame);
        }
        
        subscribe(destination, callback, headers = {}) {
            if (!this.connected) {
                throw new Error('Not connected');
            }
            
            const subscriptionId = 'sub-' + (++this.counter);
            const subscribeHeaders = Object.assign({}, headers, { 
                destination, 
                id: subscriptionId 
            });
            
            const frame = this._buildFrame('SUBSCRIBE', subscribeHeaders);
            this.ws.send(frame);
            
            this.subscriptions[subscriptionId] = callback;
            
            return {
                unsubscribe: () => {
                    const unsubscribeHeaders = { id: subscriptionId };
                    const frame = this._buildFrame('UNSUBSCRIBE', unsubscribeHeaders);
                    this.ws.send(frame);
                    delete this.subscriptions[subscriptionId];
                }
            };
        }
        
        _buildFrame(command, headers = {}, body = '') {
            let frame = command + '\n';
            
            for (const [key, value] of Object.entries(headers)) {
                frame += `${key}:${value}\n`;
            }
            
            frame += '\n';
            frame += body;
            frame += '\x00';
            
            return frame;
        }
        
        _parseFrame(data) {
            const nullByteIndex = data.indexOf('\x00');
            const frameStr = nullByteIndex >= 0 ? data.substring(0, nullByteIndex) : data;
            const lines = frameStr.split('\n');
            
            const command = lines[0];
            const headers = {};
            let body = '';
            let i = 1;
            
            // Parse headers
            for (; i < lines.length; i++) {
                const line = lines[i];
                if (line === '') break;
                const colonIndex = line.indexOf(':');
                if (colonIndex > 0) {
                    const key = line.substring(0, colonIndex);
                    const value = line.substring(colonIndex + 1);
                    headers[key] = value;
                }
            }
            
            // Parse body
            if (i < lines.length - 1) {
                body = lines.slice(i + 1).join('\n');
            }
            
            return { command, headers, body };
        }
    }
    
    function over(ws) {
        return new Client(ws);
    }
    
    exports.over = over;
    exports.Client = Client;
}));